import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormDisplay, headerActions, breadCrumbActions, headerStrings, mainStageHeaderAction, mainStageHeaderStrings } from '../../../includes';
import { Typography, Button } from '@material-ui/core';
import { colors } from '../../../../utils';
import { staffStrings } from '../config';
import { staffActions } from '../actions';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
    },
    container : {
        [theme.breakpoints.up("md")] : {
            paddingRight : 100,
            paddingLeft : 100,
        }
    },
    createBtn : {backgroundColor : colors.primary, color : colors.white}
})
class _AdminStaffRegForm extends Component {
    constructor(props) {
        super(props);
        headerActions({
            [headerStrings.headerTitle] : "New Staff (Admin)",
            [headerStrings.backButtonAction] :()=>{}
        })(props.dispatch);
        breadCrumbActions.addToBreadCrumb([
            {name : "New", path : routeNamesSchool.newAdminStaff},
        ])(props.dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : null,
            [mainStageHeaderStrings.searchActions] : null
        })(props.dispatch)
    }
    componentDidMount(){
        staffActions.getStaffForms.admin()(this.props.dispatch);
    }
    render() {
        const {classes, [staffStrings.formAdmin] : formConfig = []} = this.props;
        return (
            <div className={classes.root}>
                <FormDisplay
                    header={<Typography>New Admin Staff</Typography>}
                    classes={{root : classes.container}}
                    formConfig={formConfig}
                    footer={<div>
                        <Button 
                            className={classes.createBtn}
                            color="primary">Create
                        </Button>
                    </div>}
                    />
            </div>
        );
    }
}


_AdminStaffRegForm.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({staffReducer}) => ({
    [staffStrings.formAdmin] : staffReducer[staffStrings.formAdmin]
})


export const AdminStaffRegForm = connect(mapStateToProps)(withStyles(style)(_AdminStaffRegForm));
export {AdminStaffRegForm as default};